/*
 * bicycle_speedometer.ino — Bluetooth Bicycle Speedometer
 *
 * Elements:
 *   1. Hall-Effect Wheel Speed Sensor — pulse per revolution on D2
 *   2. SSD1306 OLED Display           — speed + distance + time
 *   3. HM-10 BLE Module               — UART JSON stream at 1 Hz
 *   4. Arduino Nano MCU               — orchestrator
 *
 * Wheel circumference: measure outside diameter of tyre on rim,
 * then C = π × D_mm.  Default: 2096 mm (700c × 25c road tyre).
 */

#include <Wire.h>
#include <Adafruit_SSD1306.h>
#include <SoftwareSerial.h>

// --- Config ---
#define HALL_PIN           2
#define WHEEL_CIRC_MM   2096.0f   // 700c × 25c
#define SPEED_TIMEOUT_US 3000000UL  // 3 s = stationary
#define DISPLAY_MS       500UL
#define BLE_MS          1000UL

// --- Objects ---
Adafruit_SSD1306 oled(128, 64, &Wire, -1);
SoftwareSerial   ble(10, 11);   // RX, TX → HM-10

// --- Globals ---
volatile unsigned long last_pulse_us = 0;
volatile unsigned long pulse_period_us = 0;

float  speed_kmh    = 0.0f;
float  dist_km      = 0.0f;
unsigned long trip_start_s;

void on_hall() {
  unsigned long t = micros();
  pulse_period_us = t - last_pulse_us;
  last_pulse_us   = t;
  dist_km += WHEEL_CIRC_MM / 1e6f;  // add one revolution in km
}

void draw_display(unsigned long elapsed_s) {
  oled.clearDisplay();
  // Speed — large
  oled.setTextSize(2);
  oled.setTextColor(SSD1306_WHITE);
  oled.setCursor(0, 0);
  oled.printf("%.1f km/h", speed_kmh);
  // Distance
  oled.setTextSize(1);
  oled.setCursor(0, 28);
  oled.printf("Dist: %.2f km", dist_km);
  // Elapsed time
  oled.setCursor(0, 44);
  oled.printf("Time: %02lu:%02lu", elapsed_s / 60, elapsed_s % 60);
  oled.display();
}

void setup() {
  Serial.begin(115200);
  ble.begin(9600);
  Wire.begin();

  oled.begin(SSD1306_SWITCHCAPVCC, 0x3C);
  oled.clearDisplay();
  oled.display();

  pinMode(HALL_PIN, INPUT_PULLUP);
  attachInterrupt(digitalPinToInterrupt(HALL_PIN), on_hall, RISING);

  trip_start_s = millis() / 1000;
  Serial.println(F("Bicycle speedometer ready."));
}

void loop() {
  static unsigned long last_display = 0;
  static unsigned long last_ble     = 0;

  unsigned long now = millis();

  // --- 1. Compute speed ---
  noInterrupts();
  unsigned long period = pulse_period_us;
  unsigned long last_p = last_pulse_us;
  interrupts();

  if ((micros() - last_p) > SPEED_TIMEOUT_US || period == 0) {
    speed_kmh = 0.0f;
  } else {
    float speed_mmps = (WHEEL_CIRC_MM * 1e6f) / (float)period;
    speed_kmh = speed_mmps * 3.6f / 1000.0f;
  }

  unsigned long elapsed_s = now / 1000 - trip_start_s;

  // --- 2. OLED refresh ---
  if (now - last_display >= DISPLAY_MS) {
    last_display = now;
    draw_display(elapsed_s);
  }

  // --- 3. BLE stream ---
  if (now - last_ble >= BLE_MS) {
    last_ble = now;
    ble.printf("{\"spd_kmh\":%.1f,\"dist_km\":%.2f,\"trip_s\":%lu}\n",
               speed_kmh, dist_km, elapsed_s);
  }
}
